sys_script_client.script:
function onChange(control, oldValue, newValue, isLoading, isTemplate) {
   if (isLoading || newValue === '') {
      return;
   }

    var req = g_form.getValue('requested_for');

	alert(req);

    if (req) {
        var ga = new GlideAjax("x_782420_loaner_0.LocationScript");
        ga.addParam("sysparm_name", "getCityCountry");
        ga.addParam("sysparm_usersysid", req);
        ga.getXMLAnswer(setLocationCallback);
    }
}

function setLocationCallback(answer) {
    if (answer) {
		alert('city and country' +answer)
        g_form.setValue('location_to_be_used', answer);
    }
}
